	scwin.f_Retrieve = async function() {

		if(acb_qryConKnd.getValue() == "품명명" || ed_qryConCd.getValue() == ""){
		  	//validation check     
            let ret = await $c.gus.cfValidate([ed_bilgLodeptCd,ica_qryConDtFm,ica_qryConDtTo]); 
	    	if(!ret){
	    		return;
	    	}
	    	//if(!cfValidate([ed_bilgLodeptCd,ica_qryConDtFm,ica_qryConDtTo])){
	    	//	return;
	    	//}
	    }

	  	//조회시작일자가 더 클경우 체크
	  	if (!$c.gus.cfIsAfterDate(ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue())) {
 	       await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
 	       return;
    	}

        /*
     	var dsHeader = "bilgLodeptCd:STRING,qryConDtFm:STRING,qryConDtTo:STRING,bilgClntNo:STRING,lineCd:STRING,"+
     	               "vsslCd:STRING,portcnt:STRING,sellVatNo:STRING,modId:STRING,qryConCd:STRING,qryConKnd:STRING,"+
     	               "impExpDomesticClsCd01:STRING,impExpDomesticClsCd02:STRING,impExpDomesticClsCd03:STRING,certiPatternCd:STRING,"+
     	               "fmlaClsCd:STRING,fmlaPatternCd:STRING,qryDtConKnd:STRING,delYn:INT,shpco:STRING,billDtl:STRING,"+
     	               "pgmId:STRING,dcsnClsCd:STRING,transCargoClsCd:STRING,upDownClsCd:STRING";
	 	ds_merchantcertilist_con.SetDataHeader(dsHeader);
 		ds_merchantcertilist_con.AddRow();
        */

     	//ds_merchantcertilist_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue());
     	//ds_merchantcertilist_con.set("qryConDtFm",   ica_qryConDtFm.getValue());
     	//ds_merchantcertilist_con.set("qryConDtTo",   ica_qryConDtTo.getValue());
     	//ds_merchantcertilist_con.set("lineCd",       ed_lineCd.getValue());
     	//ds_merchantcertilist_con.set("vsslCd",       ed_vsslCd.getValue());
     	//ds_merchantcertilist_con.set("portcnt",      ed_portcnt.getValue());
     	//ds_merchantcertilist_con.set("dcsnClsCd",    acb_dcsnClsCd.getValue());
     	//ds_merchantcertilist_con.set("modId",        ed_modId.getValue());
     	//ds_merchantcertilist_con.set("qryConKnd",    acb_qryConKnd.getValue());
        //ds_merchantcertilist_con.set("dcsnClsCd",    ""); //임시

     	ds_merchantcertilist_con.set("certiPatternCd",scwin.certiPatternCd );
     	ds_merchantcertilist_con.set("fmlaClsCd"     ,scwin.fmlaClsCd);
     	ds_merchantcertilist_con.set("delYn"         ,scwin.delYn);
     	//ds_merchantcertilist_con.set("qryConCd",ed_qryConCd.getValue());

        var pgmId_con = $c.gus.cfIsNull(scwin.p_pgmId) ? "" : scwin.p_pgmId.replace('.xml','');
        ds_merchantcertilist_con.set("pgmId",pgmId_con);

        ds_merchantcertilist.setJSON([]);
        $c.sbm.execute(sbm_merchantcertilist_retrieve);

        //ds_merchantcertilist_con.set("upDownClsCd",'NULL');
     	//if (acb_qryConKnd.getValue() == 'BILL-NO' && !$c.gus.cfIsNull(ed_qryConCd.getValue()) ) {
     	//	ds_merchantcertilist_con.set( "billDtl","Dtl")
     	//}

   		//tr_merchantcertilist_retrieve.Action = "/ds.fs.bilg.bilgrsltsmgnt.RetrieveMerchantCertiListCMD.do";
   		//tr_merchantcertilist_retrieve.Post();
	};

  	//-------------------------------------------------------------------------
  	// 팝업창 처리
  	//-------------------------------------------------------------------------
	scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {

	  	// 선언부
		var rtnList  = new Array();  // 공통POP-UP -> 요청화면 

		switch (disGubun) {
            /*
			case 1:
				//청구부서코드팝업			
				rtnList = cfCommonPopUp('retrieveOpDeptCdInfo',pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);

				cfSetReturnValue(rtnList, ed_bilgLodeptCd, ed_bilgLodeptNm);  // 청구부서코드, 청구부서명				
				break;		
			*/
	  		case 2:  			
				//LINE코드팝업			
				//rtnList = udc_comCodeGrid.cfCommonPopUp('retrieveLineInfo',pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);	  			
				//cfSetReturnValue(rtnList, ed_lineCd, ed_lineNm);  // LINE코드, LINE명

                udc_comCodeGrid.setSelectId('retrieveLineInfo');
				rtnList = udc_comCodeGrid.cfCommonPopUp(scwin.udc_comCodeGridCallback,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);	  			
				break;

	  		case 3:  		
				// 청구담당자코드 팝업			
				//rtnList = udc_modId.cfCommonPopUp('retrieveEmpInfo',pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);
				//cfSetReturnValue(rtnList, ed_modId, ed_modNm);  // 청구담당자코드, 청구담당자명

                udc_modId.setSelectId('retrieveEmpInfo');
				rtnList = udc_modId.cfCommonPopUp(scwin.udc_modIdCallback,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);	  				  			
				break;

	  		default:
	  			break;
		}

	};

  	//-------------------------------------------------------------------------
  	// 결과값 리턴
  	//-------------------------------------------------------------------------	
    scwin.f_rtnValue = function(row) {

	  	//var arrRtnVal = ds_merchantcertilist.getCellData(row, "certiNo") ;
		//window.returnValue = arrRtnVal;
		//window.close();

        var arrRtnVal = ds_merchantcertilist.getCellData(row, "certiNo") ;
        console.log('선택=>'+arrRtnVal);
        $c.win.closePopup(arrRtnVal);
	};

	//-------------------------------------------------------------------------
	// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
	//-------------------------------------------------------------------------
	scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {

		// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
		if (! await $c.gus.cfCanOpenPopup(inObj, pairObj))
			return;

		// 짝이 되는 오브젝트의 값 제거
		$c.gus.cfClearPairObj(pairObj);

		// 검색어 세팅
		var pVal = $c.gus.cfGetValue(inObj);

		// inObj가 코드 필드일 경우 팝업
		if (isCode == null || isCode == true)
			scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
		// inObj가 코드명 필드일 경우 팝업
		else
	        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');

	};

    scwin.udc_comCodeGridCallback = function(rtnList){
        $c.gus.cfSetReturnValue(rtnList, ed_lineCd, ed_lineNm);  // LINE코드, LINE명
    };

    scwin.udc_modIdCallback = function(rtnList){
        $c.gus.cfSetReturnValue(rtnList, ed_modId, ed_modNm);  // 청구담당자코드, 청구담당자명
    };

    scwin.acb_qryConKnd_onviewchange = function (info) {
        var str = acb_qryConKnd.getValue();
        if(str != "품명명"){
            ed_qryConCd.setAllowChar("A-Z0-9");
        }else{
            ed_qryConCd.setAllowChar("");
        }
    };

	//-------------------------------------------------------------------------
	// 조회조건 Clear
	//-------------------------------------------------------------------------
	scwin.f_FieldClear = function() {
console.log("필드클리어!!");
		$c.gus.cfInitObjects(tbl_search,[ed_bilgLodeptCd,ed_bilgLodeptNm,ica_qryConDtFm,ica_qryConDtTo,acb_dcsnClsCd]);
	};


scwin.sbm_merchantcertilist_retrieve_submitdone = function (e) {
	//cfHideDSWaitMsg(gr_merchantcertilist);
	//cfShowTotalRows(totalRows, rowcnt);

    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

    var rowcnt = ds_merchantcertilist.getRowCount();
	if (rowcnt == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        ica_qryConDtFm.focus();

		//cfAlertMsg(MSG_CM_WRN_002);
		//ica_qryConDtFm.Focus();				
	}

    tbx_totalRows.setValue(rowcnt);
};

scwin.sbm_merchantcertilist_retrieve_submiterror = function (e) {

};


scwin.btn_fieldClear_onclick = function (e) {
console.log("클리어!@@");
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.gr_merchantcertilist_oncelldblclick = function (rowIndex, columnIndex, columnId) {
	//if( rowIndex > 0 ){
		scwin.f_rtnValue(rowIndex);
	//}
};

